proof_block:
// Re-assert the two `forall|i|` ensures so z3 has them as concrete hypotheses.
// Their auto-instantiation triggers (`post1_self_.page_array@[i]` for run 1,
// `post2_self_.page_array@[i]` for run 2) are disjoint, so z3 never lines
// them up at the same `i` on its own.
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==>
        post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==>
        post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// Pointwise: at every index `i` in `0..NUM_PAGES`, post1 and post2 agree.
// Mentioning both `post1_self_.page_array@[i]` and `post2_self_.page_array@[i]`
// in the conclusion forces both ensures-foralls to instantiate at the same `i`.
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == index as int {
        // At `index`, every field of the page is pinned by an unconditional
        // ensures: `addr`, `state`, `is_io_page`, `rev_pointer`, `ref_count`,
        // `mappings`, `io_mappings` are each `=~=` `pre_self_.page_array@[index].*`
        // for both post1 and post2, and `owning_container` is `=~=`
        // `owning_container_op` for both. Struct-extensional `=~=` on `Page`
        // closes the case from these per-field equalities.
        assert(post1_self_.page_array@[index as int] =~= post2_self_.page_array@[index as int]);
    } else {
        // For `i != index`, both ensures-foralls fire (their triggers match
        // `post1_self_.page_array@[i]` and `post2_self_.page_array@[i]`),
        // giving `post1@[i] =~= pre@[i] =~= post2@[i]` by transitivity.
        assert(post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
        assert(post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);
    }
}

// Sequence extensionality lifts the pointwise equality to the array view:
// both views have length `NUM_PAGES` (fixed-size `Array<Page, NUM_PAGES>`),
// and they agree pointwise, so `=~=` holds.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
